apk add --no-cache python3 >/dev/null 2>&1 && python3 -c 'import os,math,json;DNA="ATGC";EXT=(".txt",".md",".json",".py",".sh",".srt",".pdf",".docx");A=lambda b,w=128:"".join(DNA[(x>>6)&3]for x in b[:w]);tau=lambda n:(lambda x:sum((2-(d*d==x))for d in range(1,int(math.isqrt(x))+1)if x%d==0))(max(2,int(n)));H=lambda b:(0.0 if not b else (lambda N,C:-sum((c/N)*math.log2(c/N)for c in C.values()))(len(b),{x:b.count(x)for x in set(b)}));idx=[];print("ESF SPECTRAL LIBRARY RUNTIME vOmega ACTIVE");[idx.append({"Book":p,"Bytes":len(b),"ByteSum":sum(b),"ATGC":A(b),"Tau":tau(sum(b)),"Entropy":round(H(b),6),"Spectral":{"CriticalAxis":0.5,"Index":int((sum(b)+tau(sum(b))+H(b)*1000+len(b))%1000003),"Coordinate":"0.5+%di"%int((sum(b)+tau(sum(b))+H(b)*1000+len(b))%1000003),"Mode":"COMPUTABLE_SYMBOLIC_INDEX"}}) or print(json.dumps(idx[-1],ensure_ascii=False,separators=(",",":"))) for r,ds,fs in os.walk(".") for f in fs if f.lower().endswith(EXT) for p in [os.path.join(r,f)] for b in [open(p,"rb").read()]];open("esf_spectral_library_index.json","w",encoding="utf-8").write(json.dumps(idx,ensure_ascii=False,indent=2));print("DONE:",len(idx),"files indexed");print("OUTPUT: esf_spectral_library_index.json")'